2	
3	import (
4		"errors"
5		"strings"
6		"testing"
7	)
8	
9	func TestReadAndDecodeJSON_Success(t *testing.T) {
10		t.Parallel()
11	
12		var got struct {
13			A string `json:"a"`
14			B int    `json:"b"`
15		}
16		err := ReadAndDecodeJSON(strings.NewReader(`{"a":"x","b":42}`), &got, false)
17		if err != nil {
18			t.Fatalf("error = %v", err)
19		}
20		if got.A != "x" || got.B != 42 {
21			t.Fatalf("got = %+v", got)
22		}
23	}
24	
25	func TestReadAndDecodeJSON_StrictRejectsUnknown(t *testing.T) {
26		t.Parallel()
27	
28		var got struct {
29			A string `json:"a"`
30		}
31		err := ReadAndDecodeJSON(strings.NewReader(`{"a":"x","extra":1}`), &got, true)
32		if err == nil {
33			t.Fatal("strict mode should reject unknown fields")
34		}
35		if errors.Is(err, ErrNonJSONResponse) {
36			t.Fatal("decode failure misclassified as non-JSON")
37		}
38	}
39	
40	func TestReadAndDecodeJSON_TolerantUnknown(t *testing.T) {
41		t.Parallel()
42	
43		var got struct {
44			A string `json:"a"`
45		}
46		err := ReadAndDecodeJSON(strings.NewReader(`{"a":"x","extra":1}`), &got, false)
47		if err != nil {
48			t.Fatalf("non-strict should accept unknown fields, got %v", err)
49		}
50	}
51	
52	func TestReadAndDecodeJSON_DetectsHTMLBody(t *testing.T) {
53		t.Parallel()
54	
55		tests := []struct {
56			name string
57			body string
58		}{
59			{"plain HTML", `<html><body>Access denied</body></html>`},
60			{"DOCTYPE", `<!DOCTYPE html><html></html>`},
61			{"leading whitespace + HTML", "   \n\t<html></html>"},
62			{"XML", `<?xml version="1.0"?><error/>`},
63		}
64	
65		for _, tt := range tests {
66			t.Run(tt.name, func(t *testing.T) {
67				t.Parallel()
68				var dest map[string]any
69				err := ReadAndDecodeJSON(strings.NewReader(tt.body), &dest, false)
70				if !errors.Is(err, ErrNonJSONResponse) {
71					t.Fatalf("error = %v, want ErrNonJSONResponse", err)
72				}
73			})
74		}
75	}
76	
77	func TestReadAndDecodeJSON_SurfacesGenuineDecodeErrors(t *testing.T) {
78		t.Parallel()
79	
80		var dest map[string]any
81		err := ReadAndDecodeJSON(strings.NewReader(`{"a": not json}`), &dest, false)
82		if err == nil {
83			t.Fatal("malformed JSON should error")
84		}
85		if errors.Is(err, ErrNonJSONResponse) {
86			t.Fatal("malformed-but-not-HTML should not be flagged as non-JSON response")
